import React from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import { graphql, useStaticQuery } from 'gatsby';
import Image from 'gatsby-image';
import {
    Timeline,
    TimelineConnector,
    TimelineContent,
    TimelineDot,
    TimelineItem,
    TimelineOppositeContent,
    TimelineSeparator,
} from '@material-ui/lab';
import { Paper, Typography } from '@material-ui/core';

// Icons
import MajorasMask from '../SVGs/ZeldaIcons/MajorasMask';
import TwilightPrincess from '../SVGs/ZeldaIcons/TwilightPrincess';
import FourSwordsAdventures from '../SVGs/ZeldaIcons/FourSwordsAdventures';

const useStyles = makeStyles((theme) => ({
    submitButton: {
        marginTop: '20px',
    },
    paper: {
        padding: '6px 16px',
        marginBottom: '10px',
        minWidth: '143px',
        maxWidth: '550px',
    },
    timelineIcon: {
        padding: '4px',
    },
    image: {
        maxWidth: '300px',
        boxShadow: '7px 7px 7px -1px rgba(0,0,0,0.63)',
        margin: '0 10px 15px 0',
    },
    timelineItem: {
        flex: 1,
    },
}));

function ChildEraTimeline() {
    const intl = useIntl();
    const classes = useStyles();
    const data = useStaticQuery(graphql`
        query {
            majorasMask: file(absolutePath: { regex: "/zelda_majoras_mask.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            twilightPrincess: file(absolutePath: { regex: "/zelda_twilight_princess.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            fourSwordsAdventures: file(absolutePath: { regex: "/zelda_four_swords_adventures.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
        }
    `);

    const {
        majorasMask,
        twilightPrincess,
        fourSwordsAdventures,
    } = data || {};

    return (
        <Timeline align="left">
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.child_era' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <MajorasMask />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.sacred_realm_protected' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.twilight_realm_and_legacy_of_hero' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.majoras_mask' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={majorasMask?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.majoras_mask' })}
                        />
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.prince_of_thieves_is_executed' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.twilight_era' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <TwilightPrincess />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.twilight_princess' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={twilightPrincess?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.twilight_princess' })}
                        />
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.shadow_invasion' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.shadow_era' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <FourSwordsAdventures className={classes.timelineIcon} />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.four_swords_adventures' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={fourSwordsAdventures?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.four_swords_adventures' })}
                        />
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.reincarnation_of_ganondorf' })}
                        </Typography>
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.resurrection_of_vaati' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
        </Timeline>
    );
}

export default ChildEraTimeline;
