import React, { useMemo } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';
import { graphql } from 'gatsby';

// Utils
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import SEO from '../components/SEO';
import Layout from '../components/Layout';

// Components
import SplitTimeline from '../components/ZeldaTimeline/SplitTimeline';
import MainTimeline from '../components/ZeldaTimeline/MainTimeline';
import UnifiedTimeline from '../components/ZeldaTimeline/UnifiedTimeline';
import FloatingControls from '../components/FloatingControls';

const useStyles = makeStyles((theme) => ({
    siteContainer: {
        maxWidth: 'none',
    },
    zeldaTimelineTitle: {
        textAlign: 'center',
    },
    iconsSourceText: {
        margin: '20px 0',
    },
}));

const ZeldaTimeline = ({ location, data, pageContext }) => {
    const intl = useIntl();
    const classes = useStyles();
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );
    const { theLegengOfZelda } = data;

    return (
        <Layout
            hideTopbar
            className={classes.siteContainer}
        >
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: 'zelda_timeline.title' })}
                ogImage={theLegengOfZelda.childImageSharp.fluid.src}
                keywords={[
                    intl.formatMessage({ id: 'seo_keywords.games' }),
                    intl.formatMessage({ id: 'seo_keywords.timeline' }),
                    'zelda',
                ]}
                alternateLangLinks={alternateLangLinks}
            />
            <FloatingControls />
            <Typography
                className={classes.zeldaTimelineTitle}
                color="textPrimary"
                variant="h3"
            >
                {intl.formatMessage({ id: 'zelda_timeline.title' })}
            </Typography>
            <MainTimeline />
            <SplitTimeline />
            <UnifiedTimeline />
            <Typography className={classes.iconsSourceText}>
                {intl.formatMessage({ id: 'zelda_timeline.icons_from' })}
            </Typography>
        </Layout>
    );
};

export default ZeldaTimeline;

export const pageQuery = graphql`
    query {
        site {
            siteMetadata {
                siteUrl
            }
        }
        theLegengOfZelda: file(absolutePath: { regex: "/zelda_skyward_sword.jpg/" }) {
            childImageSharp {
                fluid(maxWidth: 600, maxHeight: 600) {
                    ...GatsbyImageSharpFluid_tracedSVG
                }
            }
        }
    }
`;
