import React, { Fragment } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import {
    AccordionDetails,
    AccordionSummary,
    Accordion,
    Hidden,
    Step,
    Typography,
    StepConnector,
    StepLabel,
    Stepper,
} from '@material-ui/core';
import { TimelineDot } from '@material-ui/lab';
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';

// Icons
import ChildEraTimeline from './ChildEraTimeline';
import AdultEraTimeline from './AdultEraTimeline';
import HeroDefeatedIcon from '../SVGs/ZeldaIcons/HeroDefeated';
import DekuTreeIcon from '../SVGs/ZeldaIcons/DekuTree';
import RoyalFamilySymbolIcon from '../SVGs/ZeldaIcons/RoyalFamilySymbol';
import HeroDefeatedTimeline from './HeroDefeatedTimeline';

const useStyles = makeStyles((theme) => ({
    submitButton: {
        marginTop: '20px',
    },
    paper: {
        padding: '6px 16px',
        marginBottom: '10px',
        minWidth: '143px',
        maxWidth: '550px',
    },
    stepperIcon: {
        marginTop: '-8px',
    },
    timelineSplit: {
        backgroundColor: 'transparent',
        padding: '24px 0',
    },
    timelineSplitConnector: {
        padding: '0 10px',
    },
    timelineSplitConnectorLine: {
        border: '1px solid #bdbdbd',
    },
    splitTimeline: {
        display: 'flex',
    },
    accordionTitle: {
        margin: '0 auto',
    },
    accordionIcon: {
        width: '25px',
        marginBottom: '-5px',
        marginRight: '5px',
    },
    accordionDetails: {
        ...theme?.palette?.type === 'light' && { backgroundColor: '#fafafaa1' },
        ...theme?.palette?.type === 'dark' && { backgroundColor: '#303030ba' },
    },
    timelineSplitTitle: {
        textAlign: 'center',
    },
}));

const HeroDefeated = () => {
    const classes = useStyles();
    return (
        <TimelineDot color="primary" className={classes.stepperIcon}>
            <HeroDefeatedIcon />
        </TimelineDot>
    );
};

const DekuTree = () => {
    const classes = useStyles();
    return (
        <TimelineDot color="primary" className={classes.stepperIcon}>
            <DekuTreeIcon />
        </TimelineDot>
    );
};

const RoyalFamilySymbol = () => {
    const classes = useStyles();
    return (
        <TimelineDot color="primary" className={classes.stepperIcon}>
            <RoyalFamilySymbolIcon />
        </TimelineDot>
    );
};

function SplitTimeline() {
    const intl = useIntl();
    const classes = useStyles();

    return (
        <Fragment>
            <Hidden lgUp>
                <Typography
                    className={classes.timelineSplitTitle}
                    color="textPrimary"
                    variant="h6"
                >
                    {intl.formatMessage({ id: 'zelda_timeline.timeline_split' })}
                </Typography>
                <Accordion>
                    <AccordionSummary
                        expandIcon={<ExpandMoreIcon />}
                        id="hero-defeated"
                    >
                        <Typography className={classes.accordionTitle}>
                            <HeroDefeatedIcon className={classes.accordionIcon} />
                            {intl.formatMessage({ id: 'zelda_timeline.hero_defeated' })}
                        </Typography>
                    </AccordionSummary>
                    <AccordionDetails className={classes.accordionDetails}>
                        <HeroDefeatedTimeline />
                    </AccordionDetails>
                </Accordion>
                <Accordion>
                    <AccordionSummary
                        expandIcon={<ExpandMoreIcon />}
                        id="child-era"
                    >
                        <Typography className={classes.accordionTitle}>
                            <DekuTreeIcon className={classes.accordionIcon} />
                            {intl.formatMessage({ id: 'zelda_timeline.child_era' })}
                        </Typography>
                    </AccordionSummary>
                    <AccordionDetails className={classes.accordionDetails}>
                        <ChildEraTimeline />
                    </AccordionDetails>
                </Accordion>
                <Accordion>
                    <AccordionSummary
                        expandIcon={<ExpandMoreIcon />}
                        id="adult-era"
                    >
                        <Typography className={classes.accordionTitle}>
                            <RoyalFamilySymbolIcon className={classes.accordionIcon} />
                            {intl.formatMessage({ id: 'zelda_timeline.adult_era' })}
                        </Typography>
                    </AccordionSummary>
                    <AccordionDetails className={classes.accordionDetails}>
                        <AdultEraTimeline />
                    </AccordionDetails>
                </Accordion>
            </Hidden>
            <Hidden mdDown>
                <Stepper
                    className={classes.timelineSplit}
                    alternativeLabel
                    activeStep={null}
                    connector={(
                        <StepConnector
                            className={classes.timelineSplitConnector}
                            classes={{
                                line: classes.timelineSplitConnectorLine,
                            }}
                        />
                    )}
                >
                    <Step>
                        <StepLabel StepIconComponent={HeroDefeated} />
                    </Step>
                    <Step>
                        <StepLabel StepIconComponent={DekuTree} />
                    </Step>
                    <Step>
                        <StepLabel StepIconComponent={RoyalFamilySymbol} />
                    </Step>
                </Stepper>
                <div className={classes.splitTimeline}>
                    <HeroDefeatedTimeline />
                    <ChildEraTimeline />
                    <AdultEraTimeline />
                </div>
            </Hidden>
        </Fragment>
    );
}

export default SplitTimeline;
