import React, { Fragment } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import Image from 'gatsby-image';
import { graphql, useStaticQuery } from 'gatsby';
import {
    Hidden,
    Step,
    Typography,
    StepConnector,
    StepLabel,
    Stepper, Paper,
} from '@material-ui/core';
import {
    Timeline,
    TimelineConnector,
    TimelineContent,
    TimelineDot,
    TimelineItem,
    TimelineOppositeContent,
    TimelineSeparator,
} from '@material-ui/lab';

import HeroDefeatedIcon from '../SVGs/ZeldaIcons/HeroDefeated';

import DekuTreeIcon from '../SVGs/ZeldaIcons/DekuTree';
import RoyalFamilySymbolIcon from '../SVGs/ZeldaIcons/RoyalFamilySymbol';
import Triforce from '../SVGs/ZeldaIcons/Triforce';

const useStyles = makeStyles((theme) => ({
    submitButton: {
        marginTop: '20px',
    },
    paper: {
        padding: '6px 16px',
        marginBottom: '10px',
        minWidth: '143px',
        maxWidth: '550px',
    },
    stepperIcon: {
        marginTop: '-8px',
    },
    timelineSplit: {
        backgroundColor: 'transparent',
        padding: '24px 0',
    },
    timelineSplitConnector: {
        padding: '0 10px',
    },
    timelineSplitConnectorLine: {
        border: '1px solid #bdbdbd',
    },
    accordionTitle: {
        margin: '0 auto',
    },
    accordionIcon: {
        width: '25px',
        marginBottom: '-5px',
        marginRight: '5px',
    },
    accordionDetails: {
        ...theme?.palette?.type === 'light' && { backgroundColor: '#fafafaa1' },
        ...theme?.palette?.type === 'dark' && { backgroundColor: '#303030ba' },
    },
    unifiedTimelineTitle: {
        textAlign: 'center',
    },
    image: {
        maxWidth: '300px',
        boxShadow: '7px 7px 7px -1px rgba(0,0,0,0.63)',
        margin: '0 10px 15px 0',
    },
    timelineItem: {
        flex: 1,
    },
}));

const HeroDefeated = () => {
    const classes = useStyles();
    return (
        <TimelineDot color="primary" className={classes.stepperIcon}>
            <HeroDefeatedIcon />
        </TimelineDot>
    );
};

const DekuTree = () => {
    const classes = useStyles();
    return (
        <TimelineDot color="primary" className={classes.stepperIcon}>
            <DekuTreeIcon />
        </TimelineDot>
    );
};

const RoyalFamilySymbol = () => {
    const classes = useStyles();
    return (
        <TimelineDot color="primary" className={classes.stepperIcon}>
            <RoyalFamilySymbolIcon />
        </TimelineDot>
    );
};

function UnifiedTimeline() {
    const intl = useIntl();
    const classes = useStyles();
    const data = useStaticQuery(graphql`
        query {
            ageOfCalamityImage: file(absolutePath: { regex: "/zelda_age_of_calamity.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            breathOfTheWildImage: file(absolutePath: { regex: "/zelda_breath_of_the_wild.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
        }
    `);

    const {
        ageOfCalamityImage,
        breathOfTheWildImage,
    } = data || {};

    return (
        <Fragment>
            <Hidden lgUp>
                <Typography
                    className={classes.unifiedTimelineTitle}
                    color="textPrimary"
                    variant="h6"
                >
                    {intl.formatMessage({ id: 'zelda_timeline.timeline_unification' })}
                </Typography>
            </Hidden>
            <Hidden mdDown>
                <Stepper
                    className={classes.timelineSplit}
                    alternativeLabel
                    activeStep={null}
                    connector={(
                        <StepConnector
                            className={classes.timelineSplitConnector}
                            classes={{
                                line: classes.timelineSplitConnectorLine,
                            }}
                        />
                    )}
                >
                    <Step>
                        <StepLabel StepIconComponent={HeroDefeated} />
                    </Step>
                    <Step>
                        <StepLabel StepIconComponent={DekuTree} />
                    </Step>
                    <Step>
                        <StepLabel StepIconComponent={RoyalFamilySymbol} />
                    </Step>
                </Stepper>
            </Hidden>
            <Timeline align="left">
                <TimelineItem className={classes.timelineItem}>
                    <TimelineOppositeContent>
                        <Typography variant="body2" color="textSecondary">
                            {intl.formatMessage({ id: 'zelda_timeline.age_of_calamity' })}
                        </Typography>
                    </TimelineOppositeContent>
                    <TimelineSeparator>
                        <TimelineDot color="primary">
                            <Triforce />
                        </TimelineDot>
                        <TimelineConnector />
                    </TimelineSeparator>
                    <TimelineContent>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.age_of_calamity' })}
                            </Typography>
                            <Image
                                className={classes.image}
                                fluid={ageOfCalamityImage?.childImageSharp?.fluid}
                                alt={intl.formatMessage({ id: 'zelda_timeline.age_of_calamity' })}
                            />
                        </Paper>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.breath_of_the_wild' })}
                            </Typography>
                            <Image
                                className={classes.image}
                                fluid={breathOfTheWildImage?.childImageSharp?.fluid}
                                alt={intl.formatMessage({ id: 'zelda_timeline.breath_of_the_wild' })}
                            />
                        </Paper>
                    </TimelineContent>
                </TimelineItem>
            </Timeline>
        </Fragment>
    );
}

export default UnifiedTimeline;
