import React from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import { graphql, useStaticQuery } from 'gatsby';
import Image from 'gatsby-image';
import {
    Timeline,
    TimelineConnector,
    TimelineContent,
    TimelineDot,
    TimelineItem,
    TimelineOppositeContent,
    TimelineSeparator,
} from '@material-ui/lab';
import { Paper, Typography } from '@material-ui/core';

// Icons
import Triforce from '../SVGs/ZeldaIcons/Triforce';
import ALinkToThePast from '../SVGs/ZeldaIcons/ALinkToThePast';
import TheLegendOfZelda from '../SVGs/ZeldaIcons/TheLegendOfZelda';

const useStyles = makeStyles((theme) => ({
    submitButton: {
        marginTop: '20px',
    },
    paper: {
        padding: '6px 16px',
        marginBottom: '10px',
        minWidth: '143px',
        maxWidth: '550px',
    },
    timelineIcon: {
        padding: '4px',
    },
    image: {
        maxWidth: '300px',
        boxShadow: '7px 7px 7px -1px rgba(0,0,0,0.63)',
        margin: '0 10px 15px 0',
    },
    timelineItem: {
        flex: 1,
    },
}));

function HeroDefeatedTimeline() {
    const intl = useIntl();
    const classes = useStyles();
    const data = useStaticQuery(graphql`
        query {
            aLinkToThePastImage: file(absolutePath: { regex: "/zelda_a_link_to_the_past.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            oracleOfSeasonsAndAgesImage: file(absolutePath: { regex: "/zelda_oracle_of_seasons_oracle_of_ages.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            linksAwakening: file(absolutePath: { regex: "/zelda_links_awakening.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            theLegendOfZelda: file(absolutePath: { regex: "/the_legend_of_zelda.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            theAdventureOfLink: file(absolutePath: { regex: "/zelda_the_adventure_of_link.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            triForceHeroes: file(absolutePath: { regex: "/zelda_tri_force_heroes.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            aLinkBetweenWorlds: file(absolutePath: { regex: "/zelda_a_link_between_worlds.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
        }
    `);

    const {
        aLinkToThePastImage,
        oracleOfSeasonsAndAgesImage,
        linksAwakening,
        theLegendOfZelda,
        theAdventureOfLink,
        triForceHeroes,
        aLinkBetweenWorlds,
    } = data || {};

    return (
        <Timeline align="left">
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.hero_is_defeated' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <Triforce />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.decline_of_last_hero' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.the_imprisoning_war' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.era_of_dark_and_light' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <ALinkToThePast />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.a_link_to_the_past' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={aLinkToThePastImage?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.a_link_to_the_past' })}
                        />
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.resurrection_of_ganon' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.links_awakening' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={linksAwakening?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.links_awakening' })}
                        />
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.oracle_of_ages_and_seasons' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={oracleOfSeasonsAndAgesImage?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.oracle_of_ages_and_seasons' })}
                        />
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.resurrection_of_ganon' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.a_link_between_worlds' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={aLinkBetweenWorlds?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.tri_force_heroes' })}
                        />
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.tri_force_heroes' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={triForceHeroes?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.tri_force_heroes' })}
                        />
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.the_gold_era' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <Triforce />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.monarchs_of_hyrule_use_triforce' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.era_of_decline' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <TheLegendOfZelda className={classes.timelineIcon} />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.tragedy_of_princess_zelda_1' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.the_legend_of_zelda' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={theLegendOfZelda?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.the_legend_of_zelda' })}
                        />
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.resurrection_of_ganon' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.adventure_of_link' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={theAdventureOfLink?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.adventure_of_link' })}
                        />
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.resurrection_of_ganon_is_prevented' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
        </Timeline>
    );
}

export default HeroDefeatedTimeline;
