import React from 'react';
import { graphql, useStaticQuery } from 'gatsby';
import Image from 'gatsby-image';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import {
    Timeline,
    TimelineConnector,
    TimelineContent,
    TimelineDot,
    TimelineItem,
    TimelineOppositeContent,
    TimelineSeparator,
} from '@material-ui/lab';
import { Paper, Typography } from '@material-ui/core';

// Icons
import Triforce from '../SVGs/ZeldaIcons/Triforce';
import SkywardSword from '../SVGs/ZeldaIcons/SkywardSword';
import TheMinishCap from '../SVGs/ZeldaIcons/TheMinishCap';
import OcarinaOfTime from '../SVGs/ZeldaIcons/OcarinaOfTime';

const useStyles = makeStyles((theme) => ({
    submitButton: {
        marginTop: '20px',
    },
    paper: {
        padding: '6px 16px',
        marginBottom: '10px',
        minWidth: '143px',
        maxWidth: '550px',
    },
    timelineIcon: {
        padding: '4px',
    },
    image: {
        maxWidth: '300px',
        boxShadow: '7px 7px 7px -1px rgba(0,0,0,0.63)',
        margin: '0 10px 15px 0',
    },
    timelineItem: {
        flex: 1,
    },
}));

function MainTimeline() {
    const intl = useIntl();
    const classes = useStyles();
    const data = useStaticQuery(graphql`
        query {
            skywardSwordImage: file(absolutePath: { regex: "/zelda_skyward_sword.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            theMinishCapImage: file(absolutePath: { regex: "/zelda_the_minish_cap.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            fourSwords: file(absolutePath: { regex: "/zelda_four_swords.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            ocarinaOfTime: file(absolutePath: { regex: "/zelda_ocarina_of_time.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
        }
    `);

    const {
        skywardSwordImage,
        theMinishCapImage,
        fourSwords,
        ocarinaOfTime,
    } = data || {};

    return (
        <div className={classes.mainTimeline}>
            <Timeline align="left">
                <TimelineItem className={classes.timelineItem}>
                    <TimelineOppositeContent>
                        <Typography variant="body2" color="textSecondary">
                            {intl.formatMessage({ id: 'zelda_timeline.creation' })}
                        </Typography>
                    </TimelineOppositeContent>
                    <TimelineSeparator>
                        <TimelineDot color="primary">
                            <Triforce />
                        </TimelineDot>
                        <TimelineConnector />
                    </TimelineSeparator>
                    <TimelineContent>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.creation_of_land_sky' })}
                            </Typography>
                        </Paper>
                    </TimelineContent>
                </TimelineItem>
                <TimelineItem className={classes.timelineItem}>
                    <TimelineOppositeContent>
                        <Typography variant="body2" color="textSecondary">
                            {intl.formatMessage({ id: 'zelda_timeline.goddess_hylia_and_sky_era' })}
                        </Typography>
                    </TimelineOppositeContent>
                    <TimelineSeparator>
                        <TimelineDot color="primary">
                            <SkywardSword className={classes.timelineIcon} />
                        </TimelineDot>
                        <TimelineConnector />
                    </TimelineSeparator>
                    <TimelineContent>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.skyward_sword' })}
                            </Typography>
                            <Image
                                className={classes.image}
                                fluid={skywardSwordImage?.childImageSharp?.fluid}
                                alt={intl.formatMessage({ id: 'zelda_timeline.skyward_sword' })}
                            />
                            <Typography>
                                {intl.formatMessage({ id: 'zelda_timeline.the_ancient_battle' })}
                            </Typography>
                            <Typography>
                                {intl.formatMessage({ id: 'zelda_timeline.return_to_surface' })}
                            </Typography>
                        </Paper>
                    </TimelineContent>
                </TimelineItem>
                <TimelineItem className={classes.timelineItem}>
                    <TimelineOppositeContent>
                        <Typography variant="body2" color="textSecondary">
                            {intl.formatMessage({ id: 'zelda_timeline.era_of_chaos' })}
                        </Typography>
                    </TimelineOppositeContent>
                    <TimelineSeparator>
                        <TimelineDot color="primary">
                            <Triforce />
                        </TimelineDot>
                        <TimelineConnector />
                    </TimelineSeparator>
                    <TimelineContent>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.sacred_realm_sealed' })}
                            </Typography>
                        </Paper>
                    </TimelineContent>
                </TimelineItem>
                <TimelineItem className={classes.timelineItem}>
                    <TimelineOppositeContent>
                        <Typography variant="body2" color="textSecondary">
                            {intl.formatMessage({ id: 'zelda_timeline.era_of_prosperity' })}
                        </Typography>
                    </TimelineOppositeContent>
                    <TimelineSeparator>
                        <TimelineDot color="primary">
                            <Triforce />
                        </TimelineDot>
                        <TimelineConnector />
                    </TimelineSeparator>
                    <TimelineContent>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.establishment_of_hyrule' })}
                            </Typography>
                        </Paper>
                    </TimelineContent>
                </TimelineItem>
                <TimelineItem className={classes.timelineItem}>
                    <TimelineOppositeContent>
                        <Typography variant="body2" color="textSecondary">
                            {intl.formatMessage({ id: 'zelda_timeline.force_era' })}
                        </Typography>
                    </TimelineOppositeContent>
                    <TimelineSeparator>
                        <TimelineDot color="primary">
                            <TheMinishCap />
                        </TimelineDot>
                        <TimelineConnector />
                    </TimelineSeparator>
                    <TimelineContent>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.the_minish_cap' })}
                            </Typography>
                            <Image
                                className={classes.image}
                                fluid={theMinishCapImage?.childImageSharp?.fluid}
                                alt={intl.formatMessage({ id: 'zelda_timeline.the_minish_cap' })}
                            />
                            <Typography>
                                {intl.formatMessage({ id: 'zelda_timeline.rise_of_evil_vaati' })}
                            </Typography>
                        </Paper>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.four_swords' })}
                            </Typography>
                            <Image
                                className={classes.image}
                                fluid={fourSwords?.childImageSharp?.fluid}
                                alt={intl.formatMessage({ id: 'zelda_timeline.four_swords' })}
                            />
                            <Typography>
                                {intl.formatMessage({ id: 'zelda_timeline.resurrection_of_vaati' })}
                            </Typography>
                        </Paper>
                    </TimelineContent>
                </TimelineItem>
                <TimelineItem className={classes.timelineItem}>
                    <TimelineOppositeContent>
                        <Typography variant="body2" color="textSecondary">
                            {intl.formatMessage({ id: 'zelda_timeline.era_of_the_hero_of_time' })}
                        </Typography>
                    </TimelineOppositeContent>
                    <TimelineSeparator>
                        <TimelineDot color="primary">
                            <OcarinaOfTime />
                        </TimelineDot>
                        <TimelineConnector />
                    </TimelineSeparator>
                    <TimelineContent>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.hyrulean_civil_war' })}
                            </Typography>
                        </Paper>
                        <Paper elevation={3} className={classes.paper}>
                            <Typography variant="h6" component="h1">
                                {intl.formatMessage({ id: 'zelda_timeline.ocarina_of_time' })}
                            </Typography>
                            <Image
                                className={classes.image}
                                fluid={ocarinaOfTime?.childImageSharp?.fluid}
                                alt={intl.formatMessage({ id: 'zelda_timeline.ocarina_of_time' })}
                            />
                            <Typography>
                                {intl.formatMessage({ id: 'zelda_timeline.sacred_realm_becomes_dark_world' })}
                            </Typography>
                            <Typography>
                                {intl.formatMessage({ id: 'zelda_timeline.ganondorf_becomes_ganon' })}
                            </Typography>
                        </Paper>
                    </TimelineContent>
                </TimelineItem>
            </Timeline>
        </div>
    );
}

export default MainTimeline;
