import React from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import { graphql, useStaticQuery } from 'gatsby';
import Image from 'gatsby-image';
import {
    Timeline,
    TimelineConnector,
    TimelineContent,
    TimelineDot,
    TimelineItem,
    TimelineOppositeContent,
    TimelineSeparator,
} from '@material-ui/lab';
import { Paper, Typography } from '@material-ui/core';

// Icons
import Triforce from '../SVGs/ZeldaIcons/Triforce';
import TheWindWaker from '../SVGs/ZeldaIcons/TheWindWaker';
import PhantomHourglass from '../SVGs/ZeldaIcons/PhantomHourglass';
import SpiritTracks from '../SVGs/ZeldaIcons/SpiritTracks';

const useStyles = makeStyles((theme) => ({
    submitButton: {
        marginTop: '20px',
    },
    paper: {
        padding: '6px 16px',
        marginBottom: '10px',
        minWidth: '143px',
        maxWidth: '550px',
    },
    timelineIcon: {
        padding: '4px',
    },
    image: {
        maxWidth: '300px',
        boxShadow: '7px 7px 7px -1px rgba(0,0,0,0.63)',
        margin: '0 10px 15px 0',
    },
    timelineItem: {
        flex: 1,
    },
}));

function AdultEraTimeline() {
    const intl = useIntl();
    const classes = useStyles();
    const data = useStaticQuery(graphql`
        query {
            theWindWaker: file(absolutePath: { regex: "/the_wind_waker.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            phantomHourglass: file(absolutePath: { regex: "/zelda_phantom_hourglass.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
            spiritTracks: file(absolutePath: { regex: "/zelda_spirit_tracks.jpg/" }) {
                childImageSharp {
                    fluid(maxWidth: 600, maxHeight: 530) {
                        ...GatsbyImageSharpFluid_tracedSVG
                    }
                }
            }
        }
    `);

    const {
        theWindWaker,
        phantomHourglass,
        spiritTracks,
    } = data || {};

    return (
        <Timeline align="left">
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.adult_era' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <Triforce />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.ganondorf_is_sealed' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.hero_of_wind_and_new_world' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.era_without_a_hero' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <Triforce />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.ganondorf_is_resurrected' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.hyrule_is_sealed_and_flooded' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.era_of_the_great_sea' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <TheWindWaker className={classes.timelineIcon} />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.the_wind_waker' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={theWindWaker?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.the_wind_waker' })}
                        />
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.ganondorf_is_resurrected' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.era_of_the_great_voyage' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <PhantomHourglass />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.phantom_hourglass' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={phantomHourglass?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.phantom_hourglass' })}
                        />
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.new_continent_discovered' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
            <TimelineItem className={classes.timelineItem}>
                <TimelineOppositeContent>
                    <Typography variant="body2" color="textSecondary">
                        {intl.formatMessage({ id: 'zelda_timeline.era_of_hyrule_rebirth' })}
                    </Typography>
                </TimelineOppositeContent>
                <TimelineSeparator>
                    <TimelineDot color="primary">
                        <SpiritTracks />
                    </TimelineDot>
                    <TimelineConnector />
                </TimelineSeparator>
                <TimelineContent>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.new_hyrule_is_founded' })}
                        </Typography>
                    </Paper>
                    <Paper elevation={3} className={classes.paper}>
                        <Typography variant="h6" component="h1">
                            {intl.formatMessage({ id: 'zelda_timeline.spirit_tracks' })}
                        </Typography>
                        <Image
                            className={classes.image}
                            fluid={spiritTracks?.childImageSharp?.fluid}
                            alt={intl.formatMessage({ id: 'zelda_timeline.spirit_tracks' })}
                        />
                        <Typography>
                            {intl.formatMessage({ id: 'zelda_timeline.evil_king_malladus_is_resurrected' })}
                        </Typography>
                    </Paper>
                </TimelineContent>
            </TimelineItem>
        </Timeline>
    );
}

export default AdultEraTimeline;
